<template>
  <div id="app">
    <div class="container-fluid">
      <div class="row">
        <div class="col-md-12">
          <vue-tabs v-model="tabName" ref="tabs" @tab-change="handleTabChange" class="timeline--tabs">
            <v-tab id="home">
              <div slot="title">
                <span><i class="fa fa-globe"></i></span>
              </div>
              <home></home>
            </v-tab>
            
            <v-tab id="contextMenu">
              <div slot="title">
                <i class="fa fa-bars"></i>
              </div>
            </v-tab>
            <v-tab id="add" class="add">
              <div slot="title">
                <i class="fa fa-plus"></i>
              </div>
            </v-tab>

            <v-tab v-for="(t, index, key) in timelines" :key="key" :id="getTimelineTitle(t)">
              <div slot="title">
                <span :id="t" contenteditable v-html="getTimelineTitle(t)" @input="updateTimelineName"></span> <i class="fa fa-close padding-left-5" @click="removeTimeline(t)"></i>
              </div>
              <timeline :id="t"></timeline>
            </v-tab>
          </vue-tabs>
        </div>
      </div>
    </div>

    <context-menu id="context-menu" ref="ctxMenu">
      <li v-for="(t, index, key) in timelines" :key="key" @click="changeTab(t)">
        <span v-html="getTimelineTitle(t)"></span>
      </li>  
    </context-menu>

    <div class="modal fade" id="timelineModal" tabindex="-1" role="dialog" aria-labelledby="myModalLabel">
      <div class="modal-dialog" role="document">
        <div class="modal-content">
          <div class="modal-header">
            <button type="button" class="close" data-dismiss="modal" aria-label="Close"><span aria-hidden="true">&times;</span></button>
            <h4 class="modal-title" id="myModalLabel">Add Worksheet</h4>
          </div>
          <div class="modal-body">
            <div class="row">
              <div class="col-md-12">
                <div class="form-group">
                  <label :for="uid">UID</label>
                  <input type="text" class="form-control" placeholder="UID" :value="uid" @input="updateUid">
                </div>
                <div class="form-group">
                  <label :for="table">Open Table</label>
                  <input type="text" class="form-control" placeholder="Open Table" :value="table" @input="updateTable">
                </div>
              </div>
            </div>
          </div>
          <div class="modal-footer">
            <button type="button" class="btn btn-default" data-dismiss="modal">Cancel</button>
            <button type="button" class="btn btn-primary" @click="createTimeline">Add</button>
          </div>
        </div>
      </div>
    </div>

    <div class="modal fade" id="confirmModal" tabindex="-1" role="dialog" aria-labelledby="myRemoveLabel">
      <div class="modal-dialog" role="document">
        <div class="modal-content">
          <div class="modal-header">
            <button type="button" class="close" data-dismiss="modal" aria-label="Close"><span aria-hidden="true">&times;</span></button>
            <h4 class="modal-title" id="myModalLabel">Are you sure?</h4>
          </div>
          <div class="modal-body">
            Are you sure you want to delete this worksheet?
          </div>
          <div class="modal-footer">
            <button type="button" class="btn btn-default" data-dismiss="modal">Cancel</button>
            <button type="button" class="btn btn-danger" @click="removeTimelineConfirmed">Yes remove!</button>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import Routes from 'vue-tidyroutes'
import { mapMutations } from 'vuex'
import contextMenu from 'vue-context-menu'
import draggable from 'vuedraggable'
import { VueTabs, VTab } from 'vue-nav-tabs'

const jQuery = window.jQuery

const AgGrid = {
  name: 'agGrid',
  components: {
    contextMenu,
    draggable,
    VTab,
    VueTabs
  },
  computed: {
    table () {
      return this.$store.state.table
    },
    timelines: {
      get () {
        return this.$store.state.timelines
      },
      set (val) {
        this.$store.commit('updateTimelines', val)
      }
    },
    uid () {
      return this.$store.state.uid
    }
  },
  data: () => {
    return {
      addModal: null,
      removeId: undefined,
      removeModal: null,
      tabName: ''
    }
  },
  mounted () {
    // assign add modal elem
    this.addModal = jQuery(this.$el.children.timelineModal)
    this.removeModal = jQuery(this.$el.children.confirmModal)

    this.addTimeline()
    var self = this
    this.$nextTick(() => {
      self.$refs.tabs.changeTab(this.$refs.tabs.activeTabIndex, this.$refs.tabs.tabs.length - 1)
      self.$nextTick(() => {
        self.$bus.$emit('loadDefaultTimeline')
      })
    })
  },
  methods: {
    changeTab (t) {
      var tabNameId = this.getTimelineTitle(t)
      var tabIndex = this.findTabIndex(tabNameId)

      this.$refs.tabs.changeTab(this.$refs.tabs.activeTabIndex, tabIndex)
    },
    createTimeline () {
      this.addTimeline()

      // have to set it back one after adding new timeline.
      // then set it back 2 so that we are on the latest tab.
      // this.$refs.tabs.changeTab(this.$refs.tabs.activeTabIndex, this.$refs.tabs.tabs.length - 1)
      this.$nextTick(() => {
        this.addModal.modal('hide')
        this.$refs.tabs.changeTab(this.$refs.tabs.activeTabIndex, this.$refs.tabs.tabs.length - 1)
      })
    },
    findTabIndex (name) {
      return this.$refs.tabs.tabs.findIndex(t => {
        return t.id === name
      })
    },
    getTimelineTitle (t) {
      return this.$store.getters[`timelineModule${t}/timeline`].name || 'name not found'
    },
    handleTabChange (tabIndex, newTab, oldTab) {
      var remainOnCurrentTab = false
      if (newTab.id === 'add' && this.removeId === undefined) {
        this.addModal.modal('show')
        remainOnCurrentTab = true
      } else if (newTab.id === 'contextMenu') {
        this.$refs.ctxMenu.open()
        remainOnCurrentTab = true
      }

      if (remainOnCurrentTab) {
        var lastTabIndex = this.findTabIndex(oldTab.id)
        this.$refs.tabs.changeTab(tabIndex, lastTabIndex)
      }
    },
    removeTimelineConfirmed () {
      // fixes issue where vtabs active property is undefined
      var currentTabIndex = this.$refs.tabs.activeTabIndex
      if (currentTabIndex > 0) {
        this.$refs.tabs.changeTab(currentTabIndex, 0)
      }

      this.removeModal.modal('hide')
      this.$nextTick(() => {
        this.$store.commit('removeTimeline', this.removeId)
        this.$nextTick(() => {
          // this is a sub tick because removeTimeline triggers handleTabChange which auto fires again
          // to avoid this behavoir removeId is checked to ensure it is undefined.
          this.removeId = undefined
        })
      })
    },
    removeTimeline (id) {
      this.removeId = id
      this.removeModal.modal('show')
    },
    updateTable (e) {
      this.$store.commit('updateTable', e.target.value)
    },
    updateTimelineName (e) {
      clearTimeout(this.timelineNameChange)

      var self = this
      this.timelineNameChange = setTimeout(() => {
        // need a cleaner way to call the update name
        self.$store._mutations[`timelineModule${e.target.id}/updateTimelineName`][0](e.target.innerText)
      }, 400)
    },
    updateUid (e) {
      this.$store.commit('updateUid', e.target.value)
    },
    ...mapMutations([
      'addTimeline',
      'increment'
    ])
  }
}

Routes.route('/ag-grid', {
  name: 'AgGrid',
  component: AgGrid
})

export default AgGrid
</script>

<style lang="scss">
  @import '../styles/main.scss';
  
  html, body {
    margin: 0 auto;
    padding: 0;
  }
  #app {
    font-family: 'Avenir', Helvetica, Arial, sans-serif;
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
    color: #2c3e50;
    padding-top:20px;
  }
  .tab-container {
    padding-top: 15px;
  }
  .padding-left-5 {
    padding-left: 5px;
  }
</style>


