function requireAll (r, Vue) {
  r.keys().forEach(key => {
    Vue.component(r(key).default.name, r(key).default)
  })
}

const options = {
  install (Vue) {
    requireAll(require.context('../', true, /\.vue$/), Vue)
  }
}

export default options



