<template>
  <div class="row timeline">
    <div class="col-md-4">
      <div class="form-group">
        <label for="uid">User Id</label>
        <input v-model="timeline.uid" class="form-control"/>
      </div>
      <vue-tabs @tab-change="handleTabChange" class="ops--tabs" ref="timelineTabs">
        <v-tab title="Timeline">
          <div class="row" v-for="(op, key, index) in timeline.ops" :key="key">
            <div class="col-md-12">
              <div class="row">
                <div class="col-md-12">
                  <component
                    :is="getComponentType(op)"
                    :op="op"
                    :id="id"
                    @addRule="addRule"
                    @freezeAtBoth="freezeAtBoth"
                    @freezeAtColumn="freezeAtColumn"
                    @freezeAtRow="freezeAtRow"
                    @remove="remove"
                    @removeRule="removeRule">
                  </component>
                </div>
              </div>
            </div>
          </div>

          <div class="row text-center">
            <button class="btn btn-default" @click="addCompute">Add Column</button>
            <button class="btn btn-default" @click="addSelect">Add Select</button>
            <button class="btn btn-default" @click="runTimeline">Run Timeline</button>
          </div>
          <div class="row">
            <div class="col-md-12 text-center padding-top">
              <button class="btn btn-info" @click="timelineLoad">Load</button>
              <button class="btn btn-info" @click="timelineSave">Save</button>
              <button class="btn btn-info" @click="timelineRemove">Remove</button>
            </div>
          </div>
        </v-tab>

        <v-tab title="Json">
          <textarea readonly class="readonly-textarea" v-model="json"></textarea>
        </v-tab>

        <v-tab title="Macro">
          <div class="text-center" v-show="!macro">
            <img src="static/images/loading.gif" alt="loading macro data">
          </div>
          <textarea readonly class="readonly-textarea" v-show="macro" v-model="macro"></textarea>
        </v-tab>
      </vue-tabs>
    </div>
    <div class="col-md-8">
      <div class="row info">
        <div class="col-md-12">
          <span class="badge">Total Rows: {{ totalRows }}</span> <span class="badge">Load Time: {{ duration }} ms</span>
        </div>
      </div>
      <ag-grid-vue style="width: 100%; height: 500px;"
        :gridOptions="gridOptions"
        :columnDefs="gridOptions.columnDefs"
        class="ag-fresh">
      </ag-grid-vue>
    </div>
  </div>
</template>

<script>
// components
import { AgGridVue } from 'ag-grid-vue'
import { VueTabs, VTab } from 'vue-nav-tabs'
// services
import TimelineService from './timelineService'

export default {
  name: 'timeline',
  props: ['id'],
  components: {
    AgGridVue,
    VTab,
    VueTabs
  },
  data: () => {
    return {
      currentStart: 0,
      gridOptions: {
        rowModelType: 'infinite',
        paginationPageSize: 100,
        maxBlocksInCache: 10,
        maxConcurrentDatasourceRequests: 1,
        datasource: undefined,
        columnDefs: []
      },
      macro: undefined,
      macroLoading: true,
      refreshAtColumn: false,
      refreshAtRow: false
    }
  },
  computed: {
    columns () {
      return this.$store.getters[`timelineModule${this.id}/columns`]
    },
    duration () {
      return this.$store.getters[`timelineModule${this.id}/duration`]
    },
    json () {
      return JSON.stringify(this.timeline, null, 2)
    },
    refreshAt () {
      return this.refreshAtColumn || this.refreshAtRow
    },
    timeline () {
      return this.$store.getters[`timelineModule${this.id}/timeline`]
    },
    totalRows () {
      return this.$store.getters[`timelineModule${this.id}/totalRows`]
    }
  },
  created () {
    this.gridOptions.datasource = this.createDataSource()

    this.$bus.$on('loadDefaultTimeline', () => {
      this.timelineLoad()
    })
  },
  methods: {
    addCompute () {
      this.timeline.add('Compute')
    },
    addRule (op) {
      this.timeline.addRule(op)
    },
    addSelect () {
      this.timeline.add('Select')
    },
    freezeAtBoth () {
      this.refreshAtColumn = true
      this.refreshAtRow = true
    },
    freezeAtColumn () {
      this.refreshAtColumn = true
    },
    freezeAtRow () {
      this.refreshAtRow = true
    },
    getComponentType (op) {
      return op.constructor.name
    },
    handleTabChange (tabIndex, newTab, oldTab) {
      if (newTab.title === 'Macro') {
        this.macro = undefined
        this.loadMacro()
      }
    },
    loadMacro () {
      var self = this

      TimelineService.timelineAsMacro(self.timeline).then(res => {
        self.macro = res.data
      })
    },
    refreshColumn (columnName) {
      this.gridOptions.api.ensureColumnVisible(columnName)
      this.refreshAtColumn = false
    },
    refreshRow () {
      this.gridOptions.api.ensureIndexVisible(this.currentStart, 'top')
      this.refreshAtRow = false
    },
    remove (op) {
      this.timeline.remove(op)
    },
    removeRule (op, rule) {
      this.timeline.removeRule(op, rule)
    },
    runTimeline () {
      this.currentStart = this.gridOptions.api.getFirstDisplayedRow()
      this.gridOptions.api.setDatasource(this.createDataSource())
    },
    timelineLoad () {
      var self = this
      TimelineService.workspaceLoad(this.timeline.uid).then(res => {
        if (res.status === 200) {
          self.timeline.setOperations(res.data.timelines[0])
          // alert loaded
        } else {
          // alert failed to load
        }
      })
    },
    timelineSave () {
      // var self = this
      TimelineService.workspaceSave(this.timeline).then(res => {
        if (res.status === 200) {
          // alert save
        } else {
          // alert save failed
        }
      })
    },
    timelineRemove () {
      var self = this
      TimelineService.workspaceRemove(this.timeline.uid).then(res => {
        if (res.status === 200) {
          self.timeline.removeOperations()
          // alert removed
        } else {
          // alert removed failed
        }
      })
    },
    createDataSource () {
      var self = this
      return {
        getRows: (params) => {
          // clone initial object then add start and end row
          var options = JSON.parse(JSON.stringify(self.timeline))
          Object.assign(options, {
            startRow: params.startRow,
            endRow: params.endRow
          })

          TimelineService.timeline(options).then(res => {
            var grid = TimelineService.transformAgGrid(res)
            self.gridOptions.columnDefs = grid.columnDefs

            this.$store.commit(`timelineModule${this.id}/updateDuration`, res.data.duration)
            this.$store.commit(`timelineModule${this.id}/updateTotalRows`, res.data.totalRows)
            this.$store.commit(`timelineModule${this.id}/updateColumns`,
              grid.columnDefs.filter((c) => {
                return c.headerName && c.field
              }).map((c) => {
                return { name: c.headerName.replace(/\r?\n|\r/g, ' '), field: c.field }
              }))

            params.successCallback(grid.rowData, res.data.totalRows)

            if (self.refreshAt) {
              self.$nextTick(() => {
                if (self.refreshAtRow) {
                  self.refreshRow()
                }

                if (self.refreshAtColumn) {
                  self.refreshColumn(grid.columnDefs[grid.columnDefs.length - 1].field)
                }
              })
            }
          })
        }
      }
    }
  }
}
</script>

<style lang="scss">
  .timeline {
    margin-bottom: 30px;
  }
  .info {
    margin: 15px 0;
  }
  .readonly-textarea {
    height: 400px;
    width: 100%;
  }
  .badge {
    background-color: #2c3e50;
    padding: 8px;
  }
  .padding-top {
    padding-top: 15px;
  }
  .ctx-menu {
    font-size: 1em;
    padding: 10px 10px;

    & > li {
      padding: 5px 0;
    }
  }
</style>



