<template>
  <div class="panel panel-default compute">
    <div class="panel-heading">
      Column
      <button class="btn btn-danger pull-right" @click="remove">
        <i class="fa fa-trash-o"></i>
      </button>
    </div>
    <div class="panel-body">
      <div class="row">
        <div class="col-md-3 col-sm-12 no-gutter">
          <div class="form-group">
            <label :for="op.data.name">Name</label>
            <input v-model="op.data.name" class="form-control"/>
          </div>
        </div>
        <div class="col-md-3 col-sm-12 no-gutter">
          <div class="form-group">
            <label :for="op.data.label">Label</label>
            <input v-model="op.data.label" class="form-control"/>
          </div>
        </div>
        <div class="col-md-6 col-sm-12 no-gutter">
          <div class="form-group">
            <label :for="op.data.expression">Expression</label>
            <multiselect
              ref="computeSelect"
              v-model="selectedColumns"
              tag-placeholder="Add new selection"
              placeholder="Search or add a selection"
              track-by="search"
              :options="columns"
              :multiple="true"
              :taggable="true"
              :showLabels="false"
              :custom-label="columnLabel"
              :close-on-select="false"
              :clear-on-select="true"
              @tag="addTag">
            </multiselect>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import Multiselect from 'vue-multiselect'

export default {
  name: 'Compute',
  props: ['op', 'id'],
  components: {
    Multiselect
  },
  computed: {
    columns () {
      return this.$store.getters[`timelineModule${this.id}/columns`].map(c => {
        return { name: c.name, code: c.field, search: `${c.name} ${c.field}` }
      })
    }
  },
  created () {
    this.$emit('freezeAtBoth')
  },
  data: () => {
    return {
      indexer: 0,
      selectedColumns: []
    }
  },
  watch: {
    selectedColumns (selected) {
      var self = this
      // multiselect filters based on a tracked id.
      // to have the ability to add multiple of one item we need to update the tracked id.
      selected = selected.map(s => {
        s.search = s.search + '.' + self.indexer++
        return s
      })

      // this updates the model value
      this.op.data.expression = selected.map(s => {
        return s.code
      }).join(' ')
    }
  },
  methods: {
    addTag (newTag) {
      const tag = {
        name: newTag,
        code: newTag.substring(0, 2),
        typed: true
      }
      this.selectedColumns.push(tag)
    },
    columnLabel (col) {
      return col.typed ? `${col.name}` : `${col.name} - ${col.code}`
    },
    remove () {
      this.$emit('remove', this.op)
    }
  }
}
</script>

<style src="vue-multiselect/dist/vue-multiselect.min.css"></style>

<style scoped>
 .btn {
   padding: 4px 10px;
   position: relative;
   top: -5px;
 }
 .no-gutter:not(:first-of-type) {
   padding-left: 4px;
 }
 .no-gutter:not(:last-of-type) {
   padding-right: 4px;
 }
</style>

<style>
 .multiselect__content-wrapper {
  width: 300px;
 }
</style>


