import Vue from 'vue'
import Vuex from 'vuex'
import module from '../timeline/timelineDefaultStore'

// hard coded at the moment. Need to refactor
const {state: stateModule, getters, mutations} = module

Vue.use(Vuex)

// tiny table:
// table: 'pub.consumer_data.oi.ecom.test.support.report_type'

// small table
// table: 'pub.demo.baseball.batting'

// large tables:
// table: 'pub.consumer_data.oi.ecom.test.data.meow_combined'
// table: 'pub.consumer_data.oi.ecom.test.support.oi_base_table'

export const store = new Vuex.Store({
  state: {
    indexer: 1,
    table: 'pub.demo.baseball.batting',
    timelines: [],
    uid: 'oi_jcristini'
  },
  getters: {
    indexer: state => state.indexer,
    table: state => state.table,
    timelines: state => state.timelines,
    uid: state => state.uid
  },
  mutations: {
    addTimeline: (state) => {
      var newId = state.indexer++
      state.timelines.push(newId)

      store.registerModule(`timelineModule${newId}`, {
        state: stateModule,
        getters,
        mutations,
        namespaced: true // making our module reusable
      })
    },
    removeTimeline: (state, id) => {
      store.unregisterModule(`timelineModule${id}`)
      state.timelines = state.timelines.filter(t => {
        return t !== id
      })
    },
    updateTable: (state, value) => {
      state.table = value
    },
    updateTimelines: (state, value) => {
      state.timelines = value
    },
    updateUid: (state, value) => {
      state.uid = value
    }
  }
})



