<template>
  <div :class="['vue-tabs', stackedClass]">
    <div :class="[{'nav-tabs-navigation': !isStacked}, {'left-vertical-tabs': isStacked}]">
      <div :class="['nav-tabs-wrapper', stackedClass]">
        <ul :class="classList" role="tablist">
          <li v-for="(tab, key, index) in tabs"
              :key="key"
              :class="['tab', {active: isActiveTab(index)}, {disabled: tab.disabled}]"
              :id="`t-${tab.tabId}`"
              :aria-selected="isActiveTab(index)"
              :aria-controls="`p-${tab.tabId}`"
              role="tab">
            <a href="#"
                :click="(e) => {
                  e.preventDefault();
                  return false;
                }"
                :style="[isActiveTab(index) ? activeTabStyle : tabStyles(tab)]"
                :class="[{'active_tab': isActiveTab(index)}, 'tabs__link']"
                role="tab">
              
              <slot name="title" v-html="cleanSlot(tab.$slots.title)"></slot>
            </a>
          </li>
        </ul>
      </div>
    </div>
    <div :class="['tab-content', {'right-text-tabs': isStacked}]">
      <slot></slot>
    </div>
  </div>
</template>

<script>
import {VueTabs, VTab} from 'vue-nav-tabs' // eslint-disable-line no-unused-vars

export default {
  extends: VueTabs,
  name: 'tentenTabs',
  methods: {
    cleanChildren (child) {
      var self = this
      child.context = undefined
      if (child.children && child.children.length > 0) {
        child.children.map(c => {
          return self.cleanChildren(c)
        })
      }

      return child
    },
    cleanSlot (slots) {
      var self = this

      slots = slots.map(s => {
        return self.cleanChildren(s)
      })

      return slots
    },
    isActiveTab (index) {
      return this.activeTabIndex === index
    }
  }
  // ,
  // methods: {
  //   renderTabs () {
  //     return this.tabs.map((tab, index) => {
  //       if (!tab) return
  //       let {route, id, title, icon, tabId} = tab
  //       let active = this.activeTabIndex === index
  //       return (
  //         <li name="tab" onClick={() => !tab.disabled && this.navigateToTab(index, route)}
  //           class={['tab', {active: active}, {disabled: tab.disabled}]}
  //           key={title}
  //           id={`t-${tabId}`}
  //           aria-selected={active}
  //           aria-controls={`p-${tabId}`}
  //           role="tab">
  //           {this.textPosition === 'top' &&
  //           this.renderTabTitle(index, this.textPosition)
  //           }
  //           <a href="#"
  //             onClick={(e) => {
  //               e.preventDefault();
  //               return false;
  //             }}
  //             style={active ? this.activeTabStyle : this.tabStyles(tab)}
  //             class={[{'active_tab': active}, 'tabs__link']}
  //             role="tab">
  //             {this.textPosition !== 'center' && !tab.$slots.title && this.renderIcon(index)}
  //             {this.textPosition === 'center' &&
  //             this.renderTabTitle(index, this.textPosition)
  //             }
  //           </a>
  //           {this.textPosition === 'bottom' &&
  //           this.renderTabTitle(index, this.textPosition)
  //           }
  //         </li>
  //       )
  //     })
  //   }
  // }
}
</script>



