<template>
  <div class="row timeline">
    <div class="col-md-4">
      <vue-tabs class="ops--tabs">
        <v-tab title="Json">
          <textarea class="readonly-textarea" v-model="json"></textarea>
        </v-tab>
      </vue-tabs>
    </div>
    <div class="col-md-8">
      <div class="row info">
        <div class="col-md-8">
          <span class="badge">Total Rows: {{ totalRows }}</span> <span class="badge">Load Time: {{ duration }} ms</span>
        </div>
      </div>
      <div v-show="!showGrid">Loading...</div>
      <div id="hypergrid" v-show="showGrid"></div>
    </div>
  </div>
</template>

<script>
import Routes from 'vue-tidyroutes'
import TimelineService from '../../timeline/timelineService' // eslint-disable-line no-unused-vars
import HyperGrid from 'fin-hypergrid'
import fields from 'fin-hypergrid/src/lib/fields.js' // eslint-disable-line no-unused-vars
import jsonBehavior from 'fin-hypergrid/src/behaviors/JSON.js' // eslint-disable-line no-unused-vars
import HyperGridRepository from './hypergridRepository.js' // eslint-disable-line no-unused-vars

const HyperGridPage = {
  name: 'hypergrid',
  data: () => {
    return {
      showGrid: false,
      repository: undefined,

      duration: 0,
      totalRows: 0,
      grid: undefined,
      gridOptions: {
        data: [],
        margin: { bottom: '17px', right: '17px' },
        behavior: jsonBehavior,

        showRowNumbers: false,
        showFilterRow: false,
        backgroundColor: 'white',
        foregroundSelectionFont: '13px Tahoma, Geneva, sans-serif',
        columnClip: false,
        columnAutosizing: false,
        enableContinuousRepaint: true
      },
      startRow: 0,
      endRow: 100,
      timeline: {
        '_currentId': 5,
        'uid': 'oi_jcristini',
        'ops': [
          {
            'id': 1,
            'op': 'OpenTable',
            'data': {
              'table': 'pub.demo.baseball.batting'
            }
          },
          {
            'id': 2,
            'op': 'Compute',
            'data': {
              'name': 'BA',
              'label': 'BA',
              'expression': 'h / ab'
            }
          },
          {
            'id': 3,
            'op': 'Select',
            'data': {
              'rules': [
                {
                  'id': 4,
                  'term': 'year',
                  'condition': '>',
                  'value': '1990'
                }
              ]
            }
          }
        ],
        'columns': []
      }
    }
  },
  computed: {
    json () {
      return JSON.stringify(this.timeline, null, 2)
    }
  },
  mounted () {
    var self = this
    this.$nextTick(() => {
      self.$bus.$on('hyperGridScroll', (options) => {
        console.log(options)
      })

      self.queryData()
    })
  },
  methods: {
    createGrid () {
      if (!this.grid) {
        var self = this
        this.grid = new HyperGrid('#hypergrid', this.gridOptions)

        this.repository = new HyperGridRepository(this.grid, {bufferLen: 100})

        this.repository.onNewFrame = () => {
          self.showGrid = true
        }
        this.repository.onFetch = () => {
          self.showGrid = false
        }
      }
    },
    queryData () {
      var self = this
      // ensure the instance of grid is created
      self.createGrid()

      // clone initial object then add start and end row
      var options = JSON.parse(JSON.stringify(self.timeline))
      Object.assign(options, {
        startRow: self.startRow,
        endRow: self.endRow
      })
      // console.log(options)
      TimelineService.timeline(options).then(res => {
        var gridData = TimelineService.transform(res)
        gridData.dataLen = res.data.totalRows
        self.repository.handleResponse(gridData)
      })
    }
  }
}

Routes.route('/hyper-grid', {
  name: 'hyper-grid',
  component: HyperGridPage
})

export default HyperGridPage
</script>

<style>
  .readonly-textarea {
    height: 400px;
    width: 100%;
  }
</style>



