<template>
  <div class="row">
    <div class="col-md-12">
      <div id="myGrid"></div>
    </div>
  </div>
</template>

<script>
import Routes from 'vue-tidyroutes'
import { Grid } from 'slickgrid-es6'
// import { options, columns } from './grid-config'

const jQuery = window.jQuery

const SlickGrid = {
  name: 'slickgrid',
  created () {
    var columns = [
      {id: 'title', name: 'Title', field: 'title'},
      {id: 'duration', name: 'Duration', field: 'duration'},
      {id: '%', name: '% Complete', field: 'percentComplete'},
      {id: 'start', name: 'Start', field: 'start'},
      {id: 'finish', name: 'Finish', field: 'finish'},
      {id: 'effort-driven', name: 'Effort Driven', field: 'effortDriven'}
    ]
    var options = {
      enableCellNavigation: true,
      enableColumnReorder: false
    }
    jQuery(function () {
      var data = []
      for (var i = 0; i < 500; i++) {
        data[i] = {
          title: 'Task ' + i,
          duration: '5 days',
          percentComplete: Math.round(Math.random() * 100),
          start: '01/01/2009',
          finish: '01/05/2009',
          effortDriven: (i % 5 === 0)
        }
      }
      new Grid('#myGrid', data, columns, options) // eslint-disable-line no-new
    })
  }
}

Routes.route('/slick-grid', {
  name: 'slick-grid',
  component: SlickGrid
})

export default SlickGrid
</script>

<style>

</style>



