<template>
  <div>
    This is the home page
  </div>
</template>

<script>
  import Routes from 'vue-tidyroutes'

  const Home = {
    name: 'home'
  }

  Routes.route('/', {
    name: 'home',
    component: Home
  })

  export default Home
</script>

