<template>
  <div class="select-rule-container">
    <div class="row">
      <div class="col-md-4 col-sm-12 tight-gutter">
        <div class="form-group">
          <label :for="rule.term">Term {{rule.term}}</label>

          <autocomplete
            ref="autocomplete"
            :source="columns"
            v-model="rule.term"
            :initial-value="rule.term"
            input-class="form-control"
            :results-display="formattedAutocomplete"
            results-property="field"
            results-value="field">
          </autocomplete>
        </div>
        
      </div>
      <div class="col-md-3 col-sm-12 tight-gutter">
        <div class="form-group">
          <label :for="rule.condition">Condition</label>
          <input v-model="rule.condition" class="form-control"/>
        </div>
      </div>
      <div class="col-md-4 col-sm-12 tight-gutter">
        <div class="form-group">
          <label :for="rule.value">Value</label>
          <input v-model="rule.value" class="form-control"/>
        </div>
      </div>
      <div class="col-md-1 col-sm-12 tight-gutter">
        <button class="delete-btn" @click="removeRule">
          <i class="fa fa-trash-o"></i>
        </button>
      </div>
    </div>
    <div class="row label-or" v-show="!last">
      <div class="col-md-12 text-center">
        <span class="label label-primary">Or</span>
      </div>
    </div>
  </div>
</template>

<script>
import Autocomplete from 'vuejs-auto-complete'

export default {
  name: 'SelectRule',
  props: ['rule', 'last', 'id'],
  components: {
    Autocomplete
  },
  computed: {
    columns () {
      return this.$store.getters[`timelineModule${this.id}/columns`] || []
    }
  },
  watch: {
    columns () {
      this.setPredefinedValue()
    }
  },
  mounted () {
    this.setPredefinedValue()
  },
  methods: {
    formattedAutocomplete (result) {
      return result.name + ' [' + result.field + ']'
    },
    removeRule () {
      this.$emit('removeRule', this.rule)
    },
    setPredefinedValue () {
      var self = this
      this.$nextTick(() => {
        if (self.rule.term && self.columns.length > 0) {
          var value = self.$refs.autocomplete.source.filter((item) => {
            return item.field === self.rule.term
          })

          if (value) {
            self.$refs.autocomplete.setValues(value[0])
          }
        }
      })
    }
  }
}
</script>

<style scoped>
  .tight-gutter:not(:first-of-type) {
    padding-left: 4px;
  }
  .tight-gutter:not(:last-of-type) {
    padding-right: 4px;
  }
  .delete-btn {
    margin-top: 29px;
  }

  .label-or {
    margin-top: 10px;
    margin-bottom: 20px;
  }
  .label-or span {
    padding: 10px;
  }
  .btn-add-or {
    margin-top: 12px;
  }
</style>



